import{_ as a,o,c as s,ai as i,y$ as r,z0 as t,z1 as c,z2 as n,z3 as l,z4 as d,z5 as p,z6 as m,z7 as u,z8 as g,z9 as h,za as f,zb as _,zc as b,zd as P,ze as I,zf as E,zg as q,zh as S}from"./chunks/framework.DIUhWiTt.js";const B=JSON.parse('{"title":"Rutas estaticas","description":"","frontmatter":{},"headers":[],"relativePath":"notas/guias-herramientas/4.fortinet/5.Rutasestaticas/RutasEstaticas.md","filePath":"notas/guias-herramientas/4.fortinet/5.Rutasestaticas/RutasEstaticas.md"}'),T={name:"notas/guias-herramientas/4.fortinet/5.Rutasestaticas/RutasEstaticas.md"};function v(z,e,y,A,x,R){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="rutas-estaticas" tabindex="-1">Rutas estaticas <a class="header-anchor" href="#rutas-estaticas" aria-label="Permalink to “Rutas estaticas”">​</a></h1><p><img src="'+r+'" alt="20240711142743.png"></p><p>En esta practica configuraremos el Firewall de ambos sites para que tenga conectividad.</p><p>Los conectamos en el puerto numero 5.</p><h2 id="site-a" tabindex="-1">SITE A <a class="header-anchor" href="#site-a" aria-label="Permalink to “SITE A”">​</a></h2><p><img src="'+t+'" alt="20240711144600.png"></p><p><img src="'+c+'" alt="20240711145338.png"></p><h2 id="site-b" tabindex="-1">SITE B <a class="header-anchor" href="#site-b" aria-label="Permalink to “SITE B”">​</a></h2><p><img src="'+n+'" alt="20240711145819.png"></p><p><img src="'+l+'" alt="20240711145554.png"></p><p>Luego de configurarlo y probamos aun no tendremos conectividad entre las PC.</p><p><img src="'+d+'" alt="20240711150323.png"></p><p>Teniendo las direcciones IPs que se muestran en la figura, realizaremos ping de ambos lados.</p><h3 id="pc-site-a" tabindex="-1">Pc SITE A <a class="header-anchor" href="#pc-site-a" aria-label="Permalink to “Pc SITE A”">​</a></h3><p><img src="'+p+'" alt="20240711150715.png"></p><h3 id="pc-site-b" tabindex="-1">PC SITE B <a class="header-anchor" href="#pc-site-b" aria-label="Permalink to “PC SITE B”">​</a></h3><p><img src="'+m+'" alt="20240711150708.png"></p><p>Podemos ver que no tenemos acceso, esto es debido a que tenemos que crear una política y también una ruta estática.</p><h2 id="configuracion-de-rutas-estaticas" tabindex="-1">Configuración de rutas estáticas <a class="header-anchor" href="#configuracion-de-rutas-estaticas" aria-label="Permalink to “Configuración de rutas estáticas”">​</a></h2><p>Para el caso de las rutas estaticas debemos recordar el grafico:</p><p><img src="'+u+'" alt="20240711153959.png"></p><p>Entonces para el caso de configuración del SITE A tenemos que verlo de la siguiente manera: En la opción <code>Destination</code> colocaremos a donde queremos llevar que en este caso es la red <code>10.0.2.0/24</code> y colocar por que interface podemos llevar <code>Gateway</code> (IP <code>172.21.0.2</code>) que tiene conectividad con la red que en este caso es por la interface <code>port5</code>.</p><p>Para el caos de del SITE B es lo inverso, tenemos que verlo de la siguiente manera: En la opción <code>Destination</code> colocaremos a donde queremos llevar que en este caso es la red <code>10.0.1.0/24</code> y colocar por que interface podemos llevar <code>Gateway</code> (IP <code>172.21.0.1</code>) que tiene conectividad con la red que en este caso es por la interface <code>port5</code>.</p><h3 id="site-a-1" tabindex="-1">SITE A <a class="header-anchor" href="#site-a-1" aria-label="Permalink to “SITE A”">​</a></h3><p>Creamos una ruta estática.</p><p><img src="'+g+'" alt="20240711153328.png"></p><p>Luego configuraremos, en este caso colocamos a donde queremos llegar y cual es el gateway por la que podremos acceder a este. Luego seleccionamos la interface por la que se tendrá acceso a dicha red, que en este caso será <code>172.21.0.2</code></p><p><img src="'+h+'" alt="20240711153429.png"></p><h3 id="site-b-1" tabindex="-1">SITE B <a class="header-anchor" href="#site-b-1" aria-label="Permalink to “SITE B”">​</a></h3><p>Creamos una ruta estatica</p><p><img src="'+f+'" alt="20240711151816.png"></p><p>Ahora ingresamos el destino (<code>Destination</code>) a donde queremos acceder o rango de IP, en <code>Gateway</code> ingresamos la dirección IP que tiene acceso la IP que ingresamos anteriormente y luego la interface por donde tiene conectividad al otro Firewall</p><p><img src="'+_+'" alt="20240711154538.png"></p><p>Pero a pesar de configurarlo no tendremos conectividad, por lo que debemos de configurar las políticas.</p><h2 id="configuracion-de-politicas" tabindex="-1">Configuración de políticas <a class="header-anchor" href="#configuracion-de-politicas" aria-label="Permalink to “Configuración de políticas”">​</a></h2><h3 id="site-a-2" tabindex="-1">SITE A <a class="header-anchor" href="#site-a-2" aria-label="Permalink to “SITE A”">​</a></h3><p>Nos dirigimos a <code>Policy &amp; Object &gt; Firewall Policy</code> y creamos una nueva politica en ella ingresamos los siguiente:</p><ul><li>Le damos un nombre <code>TO PISO B</code>, la interface por donde ingresara el trafico <code>Incoming Interface</code>.</li><li>Interface por donde saldrá el trafico <code>Outgoing Interface</code>.</li><li>Rango o direcciones IP de las cuales se originaran el trafico <code>Source</code>.</li><li>Rango o direcciones IP a las cuales ingresara el trafico <code>Destination</code>.</li><li>En el apartado de <code>Schedule</code> se puede configurar el horario que puede permitir el trafico y en nuestro caso será siempre.</li><li>En <code>Service</code> podemos indicarle el servicio o puerto al que queremos acceder en caso nuestro es <code>ALL</code>.</li></ul><p><img src="'+b+'" alt="20240711154924.png"></p><p>Ahora hacemos lo mismo para recibir el trafico invirtiendo la interface:</p><p><img src="'+P+'" alt="20240711161321.png"></p><h3 id="site-b-2" tabindex="-1">SITE B <a class="header-anchor" href="#site-b-2" aria-label="Permalink to “SITE B”">​</a></h3><p>Realizamos lo mismos cambiando las interfaces de entrada y salida como en el SITE A.</p><p><img src="'+I+'" alt="20240711161234.png"></p><p>Lo mismo pero invirtiendo las interface para recibir el trafico.</p><p><img src="'+E+'" alt="20240711161417.png"></p><p>Luego de guardar, probaremos a realizar ping:</p><p><img src="'+q+'" alt="20240711163532.png"></p><p><img src="'+S+'" alt="20240711163606.png"></p><p>Y tenemos conectividad de ambos lados.</p>',50)])])}const C=a(T,[["render",v]]);export{B as __pageData,C as default};
